  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createSketchProject, createLayer } from '../domain/sketchModels';
  3→
  4→const SketchContext = createContext(null);
  5→const HISTORY_LIMIT = 80;
  6→
  7→function snapshotSketch(sketchProject) {
  8→  return JSON.stringify(sketchProject);
  9→}
 10→
 11→function applyUpdate(state, nextProject, recordHistory = true) {
 12→  const nextSnapshot = snapshotSketch(nextProject);
 13→  const history = recordHistory
 14→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 15→    : state.history;
 16→
 17→  return {
 18→    ...state,
 19→    history,
 20→    future: recordHistory ? [] : state.future,
 21→    project: nextProject,
 22→    isDirty: nextSnapshot !== state.savedSnapshot,
 23→  };
 24→}
 25→
 26→function updateLayer(state, layerId, updater) {
 27→  const nextLayers = state.project.layers.map((layer) =>
 28→    layer.id === layerId ? updater(layer) : layer
 29→  );
 30→  return applyUpdate(state, {
 31→    ...state.project,
 32→    updatedAt: new Date().toISOString(),
 33→    layers: nextLayers,
 34→  });
 35→}
 36→
 37→function sketchReducer(state, action) {
 38→  switch (action.type) {
 39→    case 'SKETCH_NEW': {
 40→      const newProject = action.project || createSketchProject();
 41→      return {
 42→        project: newProject,
 43→        isDirty: false,
 44→        savedSnapshot: snapshotSketch(newProject),
 45→        history: [],
 46→        future: [],
 47→      };
 48→    }
 49→
 50→    case 'SKETCH_LOAD': {
 51→      const loaded = action.project;
 52→      return {
 53→        project: loaded,
 54→        isDirty: false,
 55→        savedSnapshot: snapshotSketch(loaded),
 56→        history: [],
 57→        future: [],
 58→      };
 59→    }
 60→
 61→    case 'LAYER_ADD': {
 62→      const newLayer = action.layer || createLayer();
 63→      return applyUpdate(state, {
 64→        ...state.project,
 65→        updatedAt: new Date().toISOString(),
 66→        layers: [...state.project.layers, newLayer],
 67→      });
 68→    }
 69→
 70→    case 'LAYER_UPDATE':
 71→      return applyUpdate(state, {
 72→        ...state.project,
 73→        updatedAt: new Date().toISOString(),
 74→        layers: state.project.layers.map((layer) =>
 75→          layer.id === action.layer.id ? { ...layer, ...action.layer } : layer
 76→        ),
 77→      });
 78→
 79→    case 'LAYER_DELETE': {
 80→      if (state.project.layers.length <= 1) return state;
 81→      return applyUpdate(state, {
 82→        ...state.project,
 83→        updatedAt: new Date().toISOString(),
 84→        layers: state.project.layers.filter((layer) => layer.id !== action.layerId),
 85→      });
 86→    }
 87→
 88→    case 'LAYER_REORDER':
 89→      return applyUpdate(state, {
 90→        ...state.project,
 91→        updatedAt: new Date().toISOString(),
 92→        layers: action.layers,
 93→      });
 94→
 95→    case 'SHAPE_ADD':
 96→      return updateLayer(state, action.layerId, (layer) => ({
 97→        ...layer,
 98→        shapes: [...layer.shapes, action.shape],
 99→      }));
100→
101→    case 'SHAPE_UPDATE':
102→      return updateLayer(state, action.layerId, (layer) => ({
103→        ...layer,
104→        shapes: layer.shapes.map((shape) =>
105→          shape.id === action.shape.id ? { ...shape, ...action.shape } : shape
106→        ),
107→      }));
108→
109→    case 'SHAPE_DELETE':
110→      return updateLayer(state, action.layerId, (layer) => ({
111→        ...layer,
112→        shapes: layer.shapes.filter((shape) => shape.id !== action.shapeId),
113→      }));
114→
115→    case 'UNDO': {
116→      if (state.history.length === 0) return state;
117→      const previous = state.history[state.history.length - 1];
118→      return {
119→        ...state,
120→        project: previous,
121→        history: state.history.slice(0, -1),
122→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
123→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
124→      };
125→    }
126→
127→    case 'REDO': {
128→      if (state.future.length === 0) return state;
129→      const next = state.future[0];
130→      return {
131→        ...state,
132→        project: next,
133→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
134→        future: state.future.slice(1),
135→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
136→      };
137→    }
138→
139→    case 'MARK_SAVED':
140→      return {
141→        ...state,
142→        isDirty: false,
143→        savedSnapshot: snapshotSketch(state.project),
144→      };
145→
146→    default:
147→      return state;
148→  }
149→}
150→
151→function createInitialState(project) {
152→  return {
153→    project,
154→    isDirty: false,
155→    savedSnapshot: snapshotSketch(project),
156→    history: [],
157→    future: [],
158→  };
159→}
160→
161→export function SketchProvider({ children, initialProject }) {
162→  const [state, dispatch] = useReducer(
163→    sketchReducer,
164→    initialProject || createSketchProject(),
165→    createInitialState
166→  );
167→
168→  return (
169→    <SketchContext.Provider value={{ state, dispatch }}>
170→      {children}
171→    </SketchContext.Provider>
172→  );
173→}
174→
175→export function useSketch() {
176→  const ctx = useContext(SketchContext);
177→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
178→  const { state, dispatch } = ctx;
179→
180→  return {
181→    project: state.project,
182→    isDirty: state.isDirty,
183→    canUndo: state.history.length > 0,
184→    canRedo: state.future.length > 0,
185→    dispatch,
186→    getLayer: (layerId) => state.project.layers.find((l) => l.id === layerId) || null,
187→  };
188→}
