 13→function screenToModel(screenX, screenY, viewport, svgRect) {
 14→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 15→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 16→  return { x, y };
