.layout {
  display: grid;
  grid-template-rows: var(--toolbar-height, 52px) 1fr;
  grid-template-columns: var(--sidebar-width, 240px) 1fr;
  grid-template-areas:
    "toolbar toolbar"
    "sidebar canvas";
  height: 100%;
  width: 100%;
}

.toolbar {
  grid-area: toolbar;
  position: relative;
  z-index: 10;
}

.sidebar {
  grid-area: sidebar;
  min-height: 0;
  overflow-y: auto;
}

.canvas {
  grid-area: canvas;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
}

@media (max-width: 768px) {
  .layout {
    grid-template-columns: 0px 1fr;
  }
  .sidebar {
    position: fixed;
    top: var(--toolbar-height, 52px);
    left: 0;
    bottom: 0;
    z-index: 20;
    width: var(--sidebar-width, 240px);
    background: var(--color-panel-bg);
    box-shadow: var(--shadow-floating);
    transform: translateX(-100%);
    transition: transform var(--duration-layout) var(--ease-out);
  }
}

