import { ProjectProvider, useProject } from '@/app/ProjectProvider';
import { EditorProvider, useEditor } from '@/app/EditorProvider';
import { ClipboardProvider } from '@/app/ClipboardProvider';
import SvgCanvas from '@/renderers/SvgCanvas';
import SheetCanvas from '@/renderers/SheetCanvas';
import Toolbar from '@/ui/Toolbar';
import Sidebar from '@/ui/Sidebar';
import PropertiesPanel from '@/ui/PropertiesPanel';
import Modal from '@/ui/Modal';
import NewProjectModal from '@/ui/NewProjectModal';
import { createProject } from '@/domain/models';
import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
import {
  exportProjectFile,
  importProjectFile,
  isFilePickerAbortError,
  openProjectFile,
} from '@/persistence/fileTransfer';
import { useAutosave } from '@/persistence/useAutosave';
import { isTypingTarget } from '@/utils/keyboard';
import styles from '@/app/App.module.css';
import modalStyles from '@/ui/Modal.module.css';

const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));

function EditorShell({
  project,
  handleNew,
  handleSave,
  handleLoadClick,
  isSidebarCollapsed,
  isPropertiesCollapsed,
  onToggleSidebar,
  onToggleProperties,
}) {
  const {
    workspaceMode,
    activeSheetId,
    activeFloorId,
    maximizedPanel,
    dispatch: editorDispatch,
  } = useEditor();

  useEffect(() => {
    const sheets = project.sheets || [];
    if (!sheets.length) {
      if (activeSheetId !== null) {
        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
      }
      if (workspaceMode === 'sheet') {
        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
      }
      return;
    }

    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
    }
  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);

  return (
    <div
      className={styles.layout}
      style={{
        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
      }}
    >
      <div className={styles.toolbar}>
        <Toolbar
          onNew={handleNew}
          onSave={handleSave}
          onLoad={handleLoadClick}
          isSidebarCollapsed={isSidebarCollapsed}
          isPropertiesCollapsed={isPropertiesCollapsed}
          onToggleSidebar={onToggleSidebar}
          onToggleProperties={onToggleProperties}
        />
      </div>
      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : styles.sidebarVisible}`}>
        <Sidebar />
      </div>
      <div className={styles.canvas}>
        {workspaceMode === 'sheet' ? (
          <SheetCanvas />
        ) : (
          <div className={`${styles.modelWorkspace} ${maximizedPanel ? styles.workspaceMaximized : ''}`}>
            {maximizedPanel !== 'preview' && (
              <div className={styles.primaryCanvas}>
                <SvgCanvas />
              </div>
            )}
            {maximizedPanel !== 'canvas' && (
              <div className={styles.preview}>
                <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
                  <ThreePreviewPanel
                    project={project}
                    activeFloorId={activeFloorId}
                    isMaximized={maximizedPanel === 'preview'}
                    onToggleMaximize={() => editorDispatch({ type: 'TOGGLE_MAXIMIZE_PANEL', panel: 'preview' })}
                  />
                </Suspense>
              </div>
            )}
          </div>
        )}
      </div>
      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : styles.propertiesVisible}`}>
        <PropertiesPanel />
      </div>
    </div>
  );
}

function FloorplanInner({ isPlayground }) {
  const { project, isDirty, dispatch } = useProject();
  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
  const availablePhaseIds = useMemo(() => (project.phases || []).map((p) => p.id), [project.phases]);
  const initialActiveFloorId = getDefaultActiveFloorId(project);
  const [showLoadModal, setShowLoadModal] = useState(false);
  const [showNewProjectModal, setShowNewProjectModal] = useState(false);
  const [savedProjects, setSavedProjects] = useState([]);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
  const [projectFileHandle, setProjectFileHandle] = useState(null);
  const importInputRef = useRef(null);

  useAutosave(project, isDirty && !isPlayground, dispatch);

  // beforeunload warning
  useEffect(() => {
    const handler = (e) => {
      if (isDirty) {
        e.preventDefault();
        e.returnValue = '';
      }
    };
    window.addEventListener('beforeunload', handler);
    return () => window.removeEventListener('beforeunload', handler);
  }, [isDirty]);

  const handleNew = useCallback(() => {
    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
    setShowNewProjectModal(true);
  }, [isDirty]);

  const handleCreateProject = useCallback(({ name }) => {
    const newProject = createProject(name);
    setProjectFileHandle(null);
    dispatch({ type: 'PROJECT_NEW', project: newProject });
    setShowNewProjectModal(false);
  }, [dispatch]);

  const handleSave = useCallback(async () => {
    try {
      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
      setProjectFileHandle(fileHandle);
      try {
        await saveProject(project);
      } catch {
        // Browser draft sync is secondary to file save.
      }
      dispatch({ type: 'MARK_SAVED' });
    } catch (err) {
      if (isFilePickerAbortError(err)) return;
      alert('Failed to save project file: ' + err.message);
    }
  }, [project, projectFileHandle, dispatch]);

  // Ctrl+S save
  useEffect(() => {
    const handler = (e) => {
      if (isTypingTarget(e.target)) return;
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault();
        handleSave();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [handleSave]);

  const handleLoadClick = useCallback(async () => {
    setSavedProjects(await listProjects());
    setShowLoadModal(true);
  }, []);

  const handleOpenProjectFile = useCallback(async () => {
    if (typeof window.showOpenFilePicker !== 'function') {
      importInputRef.current?.click();
      return;
    }

    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
      return;
    }

    try {
      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
      setProjectFileHandle(fileHandle);
      setShowLoadModal(false);
    } catch (err) {
      if (isFilePickerAbortError(err)) return;
      alert('Failed to import project file: ' + err.message);
    }
  }, [isDirty, dispatch]);

  const handleImportFile = useCallback(async (e) => {
    const file = e.target.files?.[0] || null;
    e.target.value = '';
    if (!file) return;

    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
      return;
    }

    try {
      const { project: loaded, savedAt } = await importProjectFile(file);
      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
      setProjectFileHandle(null);
      setShowLoadModal(false);
    } catch (err) {
      alert('Failed to import project file: ' + err.message);
    }
  }, [isDirty, dispatch]);

  const handleLoad = useCallback(async (id) => {
    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
    try {
      const { project: loaded, savedAt } = await loadProject(id);
      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
      setProjectFileHandle(null);
      setShowLoadModal(false);
    } catch (err) {
      alert('Failed to load project: ' + err.message);
    }
  }, [isDirty, dispatch]);

  const handleDelete = useCallback(async (id, name) => {
    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
    if (!confirmed) return;

    try {
      await deleteProject(id);
      setSavedProjects(projects => projects.filter(project => project.id !== id));
    } catch (err) {
      alert('Failed to delete project: ' + err.message);
    }
  }, []);

  return (
    <EditorProvider
      initialActiveFloorId={initialActiveFloorId}
      availableFloorIds={availableFloorIds}
      availablePhaseIds={availablePhaseIds}
    >
      <input
        ref={importInputRef}
        type="file"
        accept=".json,application/json"
        onChange={handleImportFile}
        style={{ display: 'none' }}
      />

      <EditorShell
        project={project}
        handleNew={handleNew}
        handleSave={handleSave}
        handleLoadClick={handleLoadClick}
        isSidebarCollapsed={isSidebarCollapsed}
        isPropertiesCollapsed={isPropertiesCollapsed}
        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
      />

      {showNewProjectModal && (
        <NewProjectModal
          onConfirm={handleCreateProject}
          onClose={() => setShowNewProjectModal(false)}
        />
      )}

      {showLoadModal && (
        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            <div className={modalStyles.modalCard}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                <span className={modalStyles.modalCardTitle}>Project File</span>
                <span className={modalStyles.modalCardDesc}>
                  Open a JSON file previously saved to your computer.
                </span>
              </div>
              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
                Open Project File
              </button>
            </div>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
                  Stored only in this browser on this machine.
                </span>
              </div>
              {savedProjects.length === 0 ? (
                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
                  No browser drafts found.
                </p>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  {savedProjects.map(p => (
                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
                          {new Date(p.savedAt).toLocaleDateString()}
                        </span>
                      </div>
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
            Cancel
          </button>
        </Modal>
      )}
    </EditorProvider>
  );
}

export default function FloorplanWorkspace({ initialProject, isPlayground = false }) {
  return (
    <div className="editorRoot">
      <ProjectProvider initialProject={initialProject}>
        <ClipboardProvider>
          <FloorplanInner isPlayground={isPlayground} />
        </ClipboardProvider>
      </ProjectProvider>
    </div>
  );
}

import { Link } from 'react-router-dom';
import useScrollReveal from './useScrollReveal';
import FloorplanIllustration from './FloorplanIllustration';
import SketchIllustration from './SketchIllustration';
import styles from './WorkspaceCards.module.css';

export default function WorkspaceCards() {
  const floorplanRef = useScrollReveal();
  const sketchRef = useScrollReveal();

  return (
    <section className={styles.section}>
      <div className={styles.grid}>
        <Link
          to="/floorplan"
          className={`${styles.card} ${styles.cardFloorplan}`}
          ref={floorplanRef}
        >
          <div className={styles.cardBody}>
            <h3 className={styles.cardTitle}>Floorplan Editor</h3>
            <p className={styles.cardDesc}>
              Draw walls, place doors and windows, define rooms, and generate
              construction-ready documentation with millimeter precision and
              phase-based planning.
            </p>
          </div>
          <FloorplanIllustration className={styles.cardIllustration} />
        </Link>

        <Link
          to="/sketch"
          className={`${styles.card} ${styles.cardSketch}`}
          ref={sketchRef}
        >
          <div className={styles.cardBody}>
            <h3 className={styles.cardTitle}>Sketch Studio</h3>
            <p className={styles.cardDesc}>
              Freeform 2D drawing for quick concepts, site studies, and design
              explorations. Sketch freely with geometric primitives and
              annotation tools.
            </p>
          </div>
          <SketchIllustration className={styles.cardIllustration} />
        </Link>
      </div>
    </section>
  );
}

